function hasPairWithSum(sorted: number[], target: number): boolean {
  let left = 0;
  let right = sorted.length - 1;

  while (left < right) {
    const sum = sorted[left] + sorted[right];
    if (sum === target) return true;
    if (sum < target) left += 1;
    else right -= 1;
  }

  return false;
}

